// fetchEventStream.ts
import { Client } from '@generic/sdk-library';
import { MathUtils } from 'math-library';

import {
	ConsultantType,
	AssistantNewType,
	ProjectKnowledgeType,
	EstimateProduct,
	RegionRequest,
	CustomMessageType,
} from './types';

const client = new Client();

type BodyTypes =
	| ConsultantType
	| AssistantNewType
	| ProjectKnowledgeType
	| EstimateProduct
	| RegionRequest
	| undefined;

interface FetchEventStreamParams {
	userId?: string;
	projectId?: string;
	threadId?: string;
	assistantId?: string;
	body?: BodyTypes;
	interupt?: boolean;
	setStreaming?: (v: CustomMessageType[]) => void;
}

/**
 * A fetcher function that collects final data and returns it at once
 */
export async function fetchEventStream({
	userId,
	projectId,
	threadId,
	assistantId,
	body,
	interupt = false,
}: FetchEventStreamParams): Promise<{ aggregatedData: CustomMessageType[]; interupt: boolean }> {
	if (!threadId || !assistantId || !body) {
		return { aggregatedData: [], interupt: false };
	}
	let ir = false;
	const aggregatedData: CustomMessageType[] = [];
	try {
		const streamResponse = client.runs.stream(threadId, assistantId, {
			input: !interupt
				? {
						...body,
						user_id: userId,
						project_id: projectId,
				  }
				: undefined,
			command: interupt
				? {
						resume: (body as any).messages?.[0].content,
				  }
				: undefined,
			streamMode: ['messages', 'updates'],
			multitaskStrategy: 'rollback',
		});

		for await (const chunk of streamResponse) {
			// Optional validation logic commented out for clarity
			// if (chunk.event === 'messages/metadata') {
			// 	const executeNode = Object.values(chunk.data as any).map((d: any) => d)[0].metadata.node_type;
			// 	valid =
			// 		executeNode !== 'create_query' &&
			// 		executeNode !== 'journal_rag' &&
			// 		executeNode !== 'multiquery_generator' &&
			// 		executeNode !== 'generate_query_for_web' &&
			// 		executeNode !== 'rewrite_query';
			// }
			if ((chunk.event === 'messages/partial' || chunk.event === 'messages/complete') && chunk.event !== 'updates') {
				const messages = chunk.data.filter((d: any) => d.type === 'ai').map((m: any) => m);

				if (chunk.event === 'messages/complete') {
					const m = messages[0] as any;

					aggregatedData.push(m);
				} else if (
					chunk.data[0]?.response_metadata?.finish_reason === 'stop' &&
					chunk.data[0].tool_calls[0]?.args?.goto === 'human'
				) {
					aggregatedData.push({
						content: chunk.data[0].tool_calls[0].args.content,
						id: MathUtils.generateUUID(),
						eventType: 'chatbot',
						messageType: 'chatbot',
					});
				}
			}
			if (chunk.event === 'updates') {
				// eslint-disable-next-line no-underscore-dangle
				ir = chunk.data?.__interrupt__ !== undefined;
			}
		}
		return { aggregatedData, interupt: ir };
	} catch (error) {
		console.error('fetchEventStream error:', error);
		throw error;
	}
}


