export async function fetchEventStream({
    userId,
    projectId,
    threadId,
    assistantId,
    body,
    interupt = false,
}: FetchEventStreamParams): Promise<{ aggregatedData: CustomMessageType[]; interupt: boolean }> {
    if (!threadId || !assistantId || !body) {
        return { aggregatedData: [], interupt: false };
    }

    let ir = false;
    const aggregatedData: CustomMessageType[] = [];

    try {
        const streamResponse = client.runs.stream(threadId, assistantId, {
            input: !interupt
                ? {
                      ...body,
                      user_id: userId,
                      project_id: projectId,
                  }
                : undefined,
            command: interupt
                ? {
                      resume: (body as any).messages?.[0].content,
                  }
                : undefined,
            streamMode: 'messages', // Simplified streaming mode
            multitaskStrategy: 'rollback',
        });

        for await (const chunk of streamResponse) {
            // More comprehensive message handling
            if (chunk.event === 'messages/partial' || chunk.event === 'messages/complete') {
                const aiMessages = chunk.data.filter((d: any) => d.type === 'ai');

                aiMessages.forEach((message: any) => {
                    if (chunk.event === 'messages/complete' || message.response_metadata?.finish_reason === 'stop') {
                        aggregatedData.push({
                            content: message.content,
                            id: MathUtils.generateUUID(),
                            eventType: 'chatbot',
                            messageType: 'chatbot',
                        });
                    }
                });
            }

            // Separate interrupt checking
            if (chunk.event === 'updates' && chunk.data?.__interrupt__ !== undefined) {
                ir = true;
            }
        }

        return { aggregatedData, interupt: ir };
    } catch (error) {
        console.error('fetchEventStream error:', error);
        throw error;
    }
}
```

